html:
{%- set no_default_print_heading = 1 -%}
<div class="print-format">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: Arial, sans-serif; font-size: 11px; color: #000; line-height: 1.3; background: #fff; }
    .print-format { width: 100%; max-width: 100%; padding: 15px; }
    .header-title {
      text-align: center;
      font-size: 16px;
      font-weight: 700;
      margin-bottom: 8px;
      text-transform: uppercase;
      color: #000;
      letter-spacing: 0.3px;
    }
    .header-subtitle {
      text-align: center;
      font-size: 12px;
      color: #000;
      margin-bottom: 12px;
      line-height: 1.4;
    }
    .section-title {
      font-weight: 700;
      font-size: 13px;
      margin: 12px 0 8px 0;
      text-transform: uppercase;
      color: #000;
      background: #fff;
      border-bottom: 2px solid #000;
      padding: 7px 10px;
      letter-spacing: 0.3px;
    }
    .info-table {
      width: 100%;
      border-collapse: collapse;
      margin-bottom: 12px;
    }
    .info-table td {
      padding: 4px 8px;
      font-size: 12px;
      vertical-align: top;
    }
    .info-table td.label {
      font-weight: 700;
      width: 25%;
      color: #333;
    }
    .info-table td.value {
      width: 25%;
    }
    .charge-table {
      width: 100%;
      border-collapse: collapse;
      margin-bottom: 12px;
      border: 1px solid #000;
    }
    .charge-table th {
      background-color: #f0f0f0;
      color: #000;
      padding: 6px 8px;
      border: 1px solid #000;
      font-weight: 700;
      font-size: 11px;
      text-transform: uppercase;
    }
    .charge-table td {
      padding: 5px 8px;
      border: 1px solid #000;
      font-size: 11px;
    }
    .charge-table .number {
      text-align: right;
      font-family: monospace;
    }
    .total-row {
      background-color: #f0f0f0;
      font-weight: 700;
      border-top: 2px solid #000;
    }
    .notes-section {
      margin-top: 15px;
      padding: 8px;
      border: 1px solid #ccc;
      font-size: 11px;
      line-height: 1.4;
    }
    .footer {
      margin-top: 20px;
      text-align: center;
      font-size: 9px;
      color: #666;
      border-top: 1px solid #000;
      padding-top: 8px;
    }
    .signature-section {
      margin-top: 25px;
      display: flex;
      justify-content: space-between;
    }
    .signature-block {
      width: 45%;
      border-top: 1px solid #000;
      padding-top: 5px;
      font-size: 10px;
    }
    @media print {
      body { padding: 10px; margin: 0; }
      .print-format { padding: 10px; }
    }
  </style>

  <div class="header-title">{{ doc.company or 'FreightMas' }} &mdash; Invoicing Instruction</div>
  <div class="header-subtitle">
    Instruction No: {{ doc.name }} | Status: {{ doc.status }}<br>
    Date: {{ frappe.utils.formatdate(doc.requested_on, 'dd-MMM-yyyy') }}
  </div>

  <div class="section-title">Instruction Details</div>
  <table class="info-table">
    <tr>
      <td class="label">Forwarding Job:</td>
      <td class="value">{{ doc.forwarding_job }}</td>
      <td class="label">Customer:</td>
      <td class="value">{{ doc.customer or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="label">Currency:</td>
      <td class="value">{{ doc.currency or '&mdash;' }}</td>
      <td class="label">Requested By:</td>
      <td class="value">{{ doc.requested_by or '&mdash;' }}</td>
    </tr>
  </table>

  <div class="section-title">Charges to Invoice</div>
  <table class="charge-table">
    <thead>
      <tr>
        <th style="width:5%; text-align:center;">#</th>
        <th style="width:25%; text-align:left;">Charge</th>
        <th style="width:25%; text-align:left;">Description</th>
        <th style="width:15%; text-align:left;">Customer</th>
        <th style="width:10%; text-align:right;">Qty</th>
        <th style="width:10%; text-align:right;">Rate</th>
        <th style="width:10%; text-align:right;">Amount</th>
      </tr>
    </thead>
    <tbody>
      {% for item in doc.line_items %}
      <tr>
        <td style="text-align:center;">{{ loop.index }}</td>
        <td>{{ item.charge or '' }}</td>
        <td>{{ item.description or '' }}</td>
        <td>{{ item.customer or '' }}</td>
        <td class="number">{{ item.qty or 1 }}</td>
        <td class="number">{{ "{:,.2f}".format(item.sell_rate or 0) }}</td>
        <td class="number">{{ "{:,.2f}".format(item.amount or 0) }}</td>
      </tr>
      {% endfor %}
      <tr class="total-row">
        <td colspan="6" style="text-align:right;">TOTAL</td>
        <td class="number">{{ "{:,.2f}".format(doc.total_amount or 0) }}</td>
      </tr>
    </tbody>
  </table>

  {% if doc.notes %}
  <div class="section-title">Notes</div>
  <div class="notes-section">{{ doc.notes }}</div>
  {% endif %}

  <div class="signature-section">
    <div class="signature-block">
      Prepared By: {{ frappe.utils.get_fullname(doc.requested_by) or doc.requested_by }}
    </div>
    <div class="signature-block">
      Actioned By: {{ frappe.utils.get_fullname(doc.actioned_by) if doc.actioned_by else '________________' }}
    </div>
  </div>

  <div class="footer">
    <p>Generated on {{ frappe.utils.formatdate(frappe.utils.nowdate(), 'dd-MMM-yyyy') }} | {{ doc.currency or 'USD' }} | For internal use only</p>
  </div>
</div>
